const express = require('express');
const app = express();
app.use(express.json());

const PORT = process.env.PORT || 3000;

let users = {}; // Mock database for user data

// Middleware to validate user session
function validateSession(req, res, next) {
  const userId = req.headers['user-id'];
  if (!userId || !users[userId]) {
    return res.status(401).json({ error: 'Invalid session' });
  }
  req.user = users[userId];
  next();
}

// Endpoint to complete a level
app.post('/complete-level', validateSession, (req, res) => {
  const { levelId, score, time } = req.body;
  if (!levelId || typeof score !== 'number' || typeof time !== 'number') {
    return res.status(400).json({ error: 'Invalid data' });
  }

  // Simple bot detection logic
  if (score < 0 || time <= 0 || time > 3600) {
    return res.status(400).json({ error: 'Invalid game metrics' });
  }

  const user = req.user;
  user.levelsCompleted[levelId] = { score, time };

  res.json({ message: 'Level completed', levelId, score, time });
});

// Endpoint to claim rewards
app.post('/claim-reward', validateSession, (req, res) => {
  const { levelId } = req.body;
  if (!levelId || !req.user.levelsCompleted[levelId]) {
    return res.status(400).json({ error: 'Invalid levelId' });
  }

  const levelData = req.user.levelsCompleted[levelId];
  const reward = calculateReward(levelData.score, levelData.time);

  req.user.rewards.push({ levelId, reward });
  res.json({ message: 'Reward claimed', levelId, reward });
});

// Function to calculate rewards based on score and time
function calculateReward(score, time) {
  let baseReward = 100;
  let scoreMultiplier = score / 1000;
  let timeBonus = time < 300 ? 50 : 0;
  return baseReward + scoreMultiplier * 10 + timeBonus;
}

// Mock user registration
app.post('/register', (req, res) => {
  const userId = `user_${Date.now()}`;
  users[userId] = { levelsCompleted: {}, rewards: [] };
  res.json({ message: 'User registered', userId });
});

app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});